insert into tbl_scheduleattach(
	attachid, 							scheduleid,					filename, 				filepath, 				filesize,			tenant_id
) values (
	SEQ_TBL_SCHEDULEATTACH.NEXTVAL,		#v_SCHEDULEID#,				#v_FILENAME#,			#v_FILEPATH#,			#v_FILESIZE#,		#v_TENANTID#
)


insert into tbl_schedulegroupmember(
	groupid, 		memberid, 		membername, 		membername2, 		status, 	responsedate,					tenant_id
) values (
	#v_GROUPID#,	#v_MEMBERID#,	#v_MEMBERNAME#,		#v_MEMBERNAME2#,	0,			SYS_EXTRACT_UTC(SYSTIMESTAMP),	#v_TENANTID#
)


insert into tbl_schedulegroup(
	groupid, 		groupname, 			creatorid, 		creatorname, 		creatorname2, 		description,		createdate,						tenant_id		
) values (
	#v_GUID#,		#v_GROUPNAME#,		#v_USERID#,		#v_DISPLAYNAME#,	#v_DISPLAYNAME2#,	#v_DESCRIPTION#,	SYS_EXTRACT_UTC(SYSTIMESTAMP),	#v_TENANTID#
)


insert into tbl_scheduleconfig(
	userid, 		defaultview, 		startday, 		starttime, 			endtime, 			autodelete,			tenant_id		
) values (
	#v_USERID#,		#v_DEFAULTVIEW#,	#v_STARTDAY#,	#v_STARTTIME#,		#v_ENDTIME#,		#v_AUTODELETE#,		#v_TENANTID#
)


insert into tbl_secretary(
	userid, 		username, 			username2, 			secretaryid, 		secretaryname, 			tenant_id		
) values (
	#v_USERID#,		#v_DISPLAYNAME#,	#v_DISPLAYNAME2#,	#v_SECRETARYID#,	#v_SECRETARYNAME#,		#v_TENANTID#
)
